#include "ReferenceManager.h"
#include <algorithm>
namespace referencelab {
ReferenceManager::ReferenceManager(juce::File f):repository(std::move(f)),playlistsFile(repository.getFile().getSiblingFile("playlists.json")),registryFile(repository.getFile().getSiblingFile("libraries.json")){library.root=repository.getFile().getParentDirectory();LibraryDescriptor d{juce::Uuid().toString(),"Libreria principale",repository.getFile()};libraries.push_back(d);activeLibrary=d.id;}
void ReferenceManager::load(){juce::String warning;if(registryFile.existsAsFile()){auto parsed=juce::JSON::parse(registryFile);if(auto*o=parsed.getDynamicObject()){std::vector<LibraryDescriptor>found;if(auto*a=o->getProperty("libraries").getArray())for(auto&v:*a)if(auto*x=v.getDynamicObject()){LibraryDescriptor d{x->getProperty("id").toString(),x->getProperty("name").toString(),juce::File(x->getProperty("database").toString())};if(d.id.isNotEmpty()&&d.name.isNotEmpty()&&d.database!=juce::File{})found.push_back(std::move(d));}if(!found.empty()){auto selected=o->getProperty("active").toString();auto it=std::find_if(found.begin(),found.end(),[&](auto&d){return d.id==selected;});if(it==found.end())it=found.begin();libraries=found;activeLibrary=it->id;repository=MetadataRepository(it->database);playlistsFile=it->database.getSiblingFile("playlists.json");}}}auto next=repository.load(warning);std::vector<ReferencePlaylist>loaded;if(playlistsFile.existsAsFile()){auto parsed=juce::JSON::parse(playlistsFile);if(auto*a=parsed.getArray())for(auto&v:*a){juce::String error;if(auto p=ReferencePlaylist::fromVar(v,error))loaded.push_back(std::move(*p));else warning+=error+"\n";}}std::scoped_lock lock(mutex);library=std::move(next);playlists=std::move(loaded);lastWarning=warning;}
bool ReferenceManager::save(juce::String& error){return repository.save(snapshot(),error);}
bool ReferenceManager::addFile(const juce::File&f,juce::String&error){ReferenceLibrary copy=snapshot();auto root=copy.references.empty()?f.getParentDirectory():(copy.root.isDirectory()?copy.root:f.getParentDirectory());auto item=local.inspect(f,root,error);if(!item)return false;{std::scoped_lock lock(mutex);if(library.references.empty())library.root=root;auto duplicate=std::find_if(library.references.begin(),library.references.end(),[&](auto&m){return m.resolveAgainst(library.root)==f;});if(duplicate==library.references.end())library.references.push_back(std::move(*item));}return save(error);}
int ReferenceManager::scanFolder(const juce::File&folder,bool recursive,juce::String&warning){auto found=local.scan(folder,recursive,warning);int added=0;{std::scoped_lock lock(mutex);auto oldRoot=library.root;if(oldRoot!=folder)for(auto&existing:library.references)if(!juce::File::isAbsolutePath(existing.source))existing.source=existing.resolveAgainst(oldRoot).getFullPathName();library.root=folder;for(auto&item:found){auto file=item.resolveAgainst(folder);auto exists=std::find_if(library.references.begin(),library.references.end(),[&](auto&m){return m.resolveAgainst(library.root)==file;});if(exists==library.references.end()){library.references.push_back(std::move(item));++added;}}}juce::String error;if(!save(error))warning+=error;return added;}
int ReferenceManager::importCatalog(const juce::File&file,juce::String&warning){auto found=catalog.scan(file,false,warning);int added=0;{std::scoped_lock lock(mutex);for(auto&item:found){if(!juce::File::isAbsolutePath(item.source)&&!item.source.startsWithIgnoreCase("http://")&&!item.source.startsWithIgnoreCase("https://"))item.source=file.getParentDirectory().getChildFile(item.source).getFullPathName();auto duplicate=std::find_if(library.references.begin(),library.references.end(),[&](const auto&m){return m.source==item.source;});if(duplicate==library.references.end()){library.references.push_back(std::move(item));++added;}}}juce::String error;if(!save(error))warning+=(warning.isEmpty()?"":"\n")+error;return added;}
bool ReferenceManager::addUrl(const juce::String&text,juce::String&error){auto item=http.inspectUrl(juce::URL(text.trim()),error);if(!item)return false;{std::scoped_lock lock(mutex);auto duplicate=std::find_if(library.references.begin(),library.references.end(),[&](const auto&m){return m.source==item->source;});if(duplicate!=library.references.end()){error="URL gia presente nella libreria";return false;}library.references.push_back(std::move(*item));}return save(error);}
bool ReferenceManager::savePlaylists(const std::vector<ReferencePlaylist>&items,juce::String&error)const{juce::Array<juce::var>values;for(auto&p:items)values.add(p.toVar());playlistsFile.getParentDirectory().createDirectory();juce::TemporaryFile temporary(playlistsFile);if(!temporary.getFile().replaceWithText(juce::JSON::toString(values,true))||!temporary.overwriteTargetFileWithTemporary()){error="Impossibile salvare playlists.json";return false;}return true;}
bool ReferenceManager::createPlaylist(const juce::String&name,juce::String&error){auto clean=name.trim();if(clean.isEmpty()){error="Il nome della playlist e obbligatorio";return false;}auto copy=playlistsSnapshot();if(std::any_of(copy.begin(),copy.end(),[&](auto&p){return p.name.equalsIgnoreCase(clean);})){error="Esiste gia una playlist con questo nome";return false;}ReferencePlaylist item;item.name=clean;copy.push_back(std::move(item));if(!savePlaylists(copy,error))return false;{std::scoped_lock lock(mutex);playlists=std::move(copy);}return true;}
bool ReferenceManager::addToPlaylist(const juce::String&pid,const juce::String&rid,juce::String&error){auto copy=playlistsSnapshot();auto p=std::find_if(copy.begin(),copy.end(),[&](auto&x){return x.id==pid;});if(p==copy.end()){error="Playlist non trovata";return false;}{std::scoped_lock lock(mutex);if(std::none_of(library.references.begin(),library.references.end(),[&](auto&r){return r.uuid==rid;})){error="Reference non trovata";return false;}}if(!p->add(rid)){error="Reference gia presente nella playlist";return false;}if(!savePlaylists(copy,error))return false;{std::scoped_lock lock(mutex);playlists=std::move(copy);}return true;}
bool ReferenceManager::removeFromPlaylist(const juce::String&pid,const juce::String&rid,juce::String&error){auto copy=playlistsSnapshot();auto p=std::find_if(copy.begin(),copy.end(),[&](auto&x){return x.id==pid;});if(p==copy.end()||!p->remove(rid)){error="Reference non presente nella playlist";return false;}if(!savePlaylists(copy,error))return false;{std::scoped_lock lock(mutex);playlists=std::move(copy);}return true;}
std::optional<ReferenceMetadata> ReferenceManager::selectPlaylistRelative(const juce::String&pid,int delta,juce::String&error){auto copy=playlistsSnapshot();auto p=std::find_if(copy.begin(),copy.end(),[&](auto&x){return x.id==pid;});if(p==copy.end()||p->referenceIds.isEmpty()){error="Playlist vuota o non trovata";return{};}auto id=p->selectRelative(delta);std::optional<ReferenceMetadata>result;{std::scoped_lock lock(mutex);auto r=std::find_if(library.references.begin(),library.references.end(),[&](auto&x){return x.uuid==id;});if(r!=library.references.end())result=*r;}if(!result){error="La reference della playlist non esiste piu";return{};}if(!savePlaylists(copy,error))return{};{std::scoped_lock lock(mutex);playlists=std::move(copy);}return result;}
std::vector<ReferencePlaylist> ReferenceManager::playlistsSnapshot()const{std::scoped_lock lock(mutex);return playlists;}
std::vector<LibraryDescriptor> ReferenceManager::librariesSnapshot()const{std::scoped_lock lock(mutex);return libraries;}
juce::String ReferenceManager::activeLibraryId()const{std::scoped_lock lock(mutex);return activeLibrary;}
bool ReferenceManager::saveRegistry(const std::vector<LibraryDescriptor>&items,const juce::String&active,juce::String&error)const{auto*root=new juce::DynamicObject();root->setProperty("active",active);juce::Array<juce::var>values;for(auto&d:items){auto*o=new juce::DynamicObject();o->setProperty("id",d.id);o->setProperty("name",d.name);o->setProperty("database",d.database.getFullPathName());values.add(o);}root->setProperty("libraries",values);registryFile.getParentDirectory().createDirectory();juce::TemporaryFile temporary(registryFile);if(!temporary.getFile().replaceWithText(juce::JSON::toString(juce::var(root),true))||!temporary.overwriteTargetFileWithTemporary()){error="Impossibile salvare il registro librerie";return false;}return true;}
bool ReferenceManager::createLibrary(const juce::String&name,const juce::File&folder,juce::String&error){auto clean=name.trim();if(clean.isEmpty()||folder==juce::File{}){error="Nome e cartella sono obbligatori";return false;}if(!folder.createDirectory()){error="Impossibile creare la cartella della libreria";return false;}auto copy=librariesSnapshot();auto database=folder.getChildFile("reference.json");if(std::any_of(copy.begin(),copy.end(),[&](auto&d){return d.name.equalsIgnoreCase(clean)||d.database==database;})){error="Libreria gia registrata";return false;}LibraryDescriptor d{juce::Uuid().toString(),clean,database};copy.push_back(d);if(!saveRegistry(copy,d.id,error))return false;{std::scoped_lock lock(mutex);libraries=copy;activeLibrary=d.id;}load();return true;}
bool ReferenceManager::switchLibrary(const juce::String&id,juce::String&error){auto copy=librariesSnapshot();if(std::none_of(copy.begin(),copy.end(),[&](auto&d){return d.id==id;})){error="Libreria non trovata";return false;}juce::String saveError;if(!save(saveError)){error=saveError;return false;}if(!saveRegistry(copy,id,error))return false;{std::scoped_lock lock(mutex);activeLibrary=id;}load();return true;}
bool ReferenceManager::remove(const juce::String&id,juce::String&error){{std::scoped_lock lock(mutex);std::erase_if(library.references,[&](auto&m){return m.uuid==id;});}return save(error);}
bool ReferenceManager::updateMetadata(const ReferenceMetadata&updated,juce::String&error){if(updated.uuid.isEmpty()||updated.title.trim().isEmpty()||updated.source.isEmpty()){error="UUID, titolo e sorgente sono obbligatori";return false;}if(updated.rating&&(*updated.rating<0||*updated.rating>5)){error="Il rating deve essere compreso tra 0 e 5";return false;}{std::scoped_lock lock(mutex);auto it=std::find_if(library.references.begin(),library.references.end(),[&](auto&m){return m.uuid==updated.uuid;});if(it==library.references.end()){error="Reference non trovata";return false;}*it=updated;}return save(error);}
bool ReferenceManager::relink(const juce::String&id,const juce::File&file,juce::String&error){auto copy=snapshot();auto inspected=local.inspect(file,copy.root,error);if(!inspected)return false;{std::scoped_lock lock(mutex);auto it=std::find_if(library.references.begin(),library.references.end(),[&](auto&m){return m.uuid==id;});if(it==library.references.end()){error="Reference non trovata";return false;}it->source=inspected->source;it->durationSeconds=inspected->durationSeconds;it->sampleRate=inspected->sampleRate;it->channels=inspected->channels;it->sizeBytes=inspected->sizeBytes;it->lastModified=inspected->lastModified;}return save(error);}
bool ReferenceManager::matches(const ReferenceMetadata&m,const juce::String&q){auto needle=q.trim().toLowerCase();if(needle.isEmpty())return true;juce::String hay=m.title+" "+m.artist+" "+m.album+" "+m.genre+" "+m.notes+" "+m.tags.joinIntoString(" ");return hay.toLowerCase().contains(needle);}
std::vector<ReferenceMetadata> ReferenceManager::search(const juce::String&q)const{std::scoped_lock lock(mutex);std::vector<ReferenceMetadata> out;for(auto&m:library.references)if(matches(m,q))out.push_back(m);return out;}
std::vector<ReferenceMetadata> ReferenceManager::filter(const ReferenceFilter&f)const{std::scoped_lock lock(mutex);std::vector<ReferenceMetadata> out;for(auto&m:library.references){auto bpm=m.bpm.value_or(0);if(!matches(m,f.query)||(f.favouritesOnly&&!m.favourite)||m.rating.value_or(0)<f.minimumRating||(f.artist.isNotEmpty()&&!m.artist.containsIgnoreCase(f.artist))||(f.genre.isNotEmpty()&&!m.genre.containsIgnoreCase(f.genre))||(f.musicalKey.isNotEmpty()&&!m.musicalKey.equalsIgnoreCase(f.musicalKey))||bpm<f.minimumBpm||bpm>f.maximumBpm)continue;out.push_back(m);}auto compare=[&](const auto&a,const auto&b){int result=0;switch(f.sort){case ReferenceSort::title:result=a.title.compareIgnoreCase(b.title);break;case ReferenceSort::artist:result=a.artist.compareIgnoreCase(b.artist);break;case ReferenceSort::genre:result=a.genre.compareIgnoreCase(b.genre);break;case ReferenceSort::bpm:result=a.bpm.value_or(0)<b.bpm.value_or(0)?-1:a.bpm.value_or(0)>b.bpm.value_or(0)?1:0;break;case ReferenceSort::rating:result=a.rating.value_or(0)-b.rating.value_or(0);break;case ReferenceSort::dateAdded:result=a.dateAdded<b.dateAdded?-1:a.dateAdded>b.dateAdded?1:0;break;case ReferenceSort::lastUsed:result=a.lastUsed<b.lastUsed?-1:a.lastUsed>b.lastUsed?1:0;break;}return f.ascending?result<0:result>0;};std::stable_sort(out.begin(),out.end(),compare);return out;}
ReferenceLibrary ReferenceManager::snapshot()const{std::scoped_lock lock(mutex);return library;}
juce::String ReferenceManager::getLastWarning()const{std::scoped_lock lock(mutex);return lastWarning;}
}
